import { createContext, useContext, useState, useEffect, ReactNode } from "react";
import { storage, Client, Project, Employee, Task, DataContextType } from "../services/storage";

const DataContext = createContext<DataContextType | undefined>(undefined);

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) {
    throw new Error("useData must be used within a DataProvider");
  }
  return context;
};

export const DataProvider = ({ children }: { children: ReactNode }) => {
  // --- Initial State ---
  const [clients, setClients] = useState<Client[]>(() => storage.getClients());
  const [projects, setProjects] = useState<Project[]>(() => storage.getProjects());
  const [employees, setEmployees] = useState<Employee[]>(() => storage.getEmployees());
  const [tasks, setTasks] = useState<Task[]>(() => storage.getTasks());

  // --- Persistence Logic ---
  useEffect(() => { storage.saveClients(clients); }, [clients]);
  useEffect(() => { storage.saveProjects(projects); }, [projects]);
  useEffect(() => { storage.saveEmployees(employees); }, [employees]);
  useEffect(() => { storage.saveTasks(tasks); }, [tasks]);

  // --- Logic Functions ---

  // Clients
  const addClient = (client: Omit<Client, 'id'>) => {
    setClients([...clients, { ...client, id: Date.now().toString() }]);
  };

  const editClient = (updatedClient: Client) => {
    setClients(clients.map(client => client.id === updatedClient.id ? updatedClient : client));
  };

  const deleteClient = (id: string) => {
    setClients(clients.filter(client => client.id !== id));
    setProjects(projects.filter(project => project.clientId !== id));
  };

  // Projects
  const addProject = (project: Omit<Project, 'id'>) => {
    setProjects([...projects, { ...project, id: Date.now().toString() }]);
  };

  const editProject = (updatedProject: Project) => {
    setProjects(projects.map(project => project.id === updatedProject.id ? updatedProject : project));
  };

  const deleteProject = (id: string) => {
    setProjects(projects.filter(project => project.id !== id));
    setTasks(tasks.filter(task => task.projectId !== id));
  };

  // Employees
  const addEmployee = (employee: Omit<Employee, 'id'>) => {
    setEmployees([...employees, { ...employee, id: Date.now().toString() }]);
  };

  const editEmployee = (updatedEmployee: Employee) => {
    setEmployees(employees.map(employee => employee.id === updatedEmployee.id ? updatedEmployee : employee));
  };

  const deleteEmployee = (id: string) => {
    setEmployees(employees.filter(employee => employee.id !== id));
    setTasks(tasks.map(task => task.employeeId === id ? { ...task, employeeId: null } : task));
  };

  // Tasks
  const addTask = (task: Omit<Task, 'id'>) => {
    setTasks([...tasks, { ...task, id: Date.now().toString() }]);
  };

  const updateTaskStatus = (taskId: string, status: Task['status']) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, status } : t));
  };

  const deleteTask = (taskId: string) => {
    setTasks(tasks.filter(t => t.id !== taskId));
  };

  const value: DataContextType = {
    clients, addClient, editClient, deleteClient,
    projects, addProject, editProject, deleteProject,
    employees, addEmployee, editEmployee, deleteEmployee,
    tasks, addTask, updateTaskStatus, deleteTask
  };

  return (
    <DataContext.Provider value={value}>
      {children}
    </DataContext.Provider>
  );
};
